"""Launch Interceptor Program decision logic.

This module provides:
- realcompare(a, b): six-significant-digit real comparison.
- decide(...): Python embedding of the Pascal DECIDE procedure.
"""

from __future__ import annotations

from decimal import Decimal
from math import acos, hypot
from typing import Dict, List, Tuple

PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """Compare real numbers to six significant digits.

    Returns one of: "LT", "EQ", "GT".
    """

    da = Decimal(f"{a:.6g}")
    db = Decimal(f"{b:.6g}")
    if da < db:
        return "LT"
    if da > db:
        return "GT"
    return "EQ"


def decide(
    numpoints: int,
    x: List[float],
    y: List[float],
    parameters: Dict[str, float],
    lcm: List[List[str]],
    pum_diag: List[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    """Behavioral equivalent of DECIDE from the 1986 specification."""

    def lt(a: float, b: float) -> bool:
        return realcompare(a, b) == "LT"

    def gt(a: float, b: float) -> bool:
        return realcompare(a, b) == "GT"

    def eq(a: float, b: float) -> bool:
        return realcompare(a, b) == "EQ"

    def ge(a: float, b: float) -> bool:
        return realcompare(a, b) in ("GT", "EQ")

    def distance(i: int, j: int) -> float:
        return hypot(x[j] - x[i], y[j] - y[i])

    def point_eq(i: int, j: int) -> bool:
        return eq(x[i], x[j]) and eq(y[i], y[j])

    def triangle_area(i: int, j: int, k: int) -> float:
        return abs(
            x[i] * (y[j] - y[k])
            + x[j] * (y[k] - y[i])
            + x[k] * (y[i] - y[j])
        ) / 2.0

    def angle_condition(i: int, j: int, k: int, epsilon: float) -> bool:
        if point_eq(i, j) or point_eq(k, j):
            return False

        v1x = x[i] - x[j]
        v1y = y[i] - y[j]
        v2x = x[k] - x[j]
        v2y = y[k] - y[j]
        n1 = hypot(v1x, v1y)
        n2 = hypot(v2x, v2y)
        if eq(n1, 0.0) or eq(n2, 0.0):
            return False

        cosang = (v1x * v2x + v1y * v2y) / (n1 * n2)
        if cosang > 1.0:
            cosang = 1.0
        elif cosang < -1.0:
            cosang = -1.0
        angle = acos(cosang)

        return lt(angle, PI - epsilon) or gt(angle, PI + epsilon)

    def required_circle_radius(i: int, j: int, k: int) -> float:
        a = distance(j, k)
        b = distance(i, k)
        c = distance(i, j)
        lengths = [a, b, c]
        longest = max(lengths)

        area = triangle_area(i, j, k)
        if eq(area, 0.0):
            return longest / 2.0

        sq = sorted([a * a, b * b, c * c])
        if ge(sq[2], sq[0] + sq[1]):
            return longest / 2.0

        return (a * b * c) / (4.0 * area)

    def cannot_fit_circle(i: int, j: int, k: int, radius: float) -> bool:
        return gt(required_circle_radius(i, j, k), radius)

    def quadrant(i: int) -> int:
        xi = x[i]
        yi = y[i]
        if ge(xi, 0.0) and ge(yi, 0.0):
            return 1
        if lt(xi, 0.0) and ge(yi, 0.0):
            return 2
        if ge(0.0, xi) and lt(yi, 0.0):
            return 3
        return 4

    def point_line_distance(px: float, py: float, ax: float, ay: float, bx: float, by: float) -> float:
        num = abs((by - ay) * px - (bx - ax) * py + bx * ay - by * ax)
        den = hypot(by - ay, bx - ax)
        if eq(den, 0.0):
            return hypot(px - ax, py - ay)
        return num / den

    p = parameters
    length1 = float(p["LENGTH1"])
    radius1 = float(p["RADIUS1"])
    epsilon = float(p["EPSILON"])
    area1 = float(p["AREA1"])
    q_pts = int(p["Q_PTS"])
    quads = int(p["QUADS"])
    dist = float(p["DIST"])
    n_pts = int(p["N_PTS"])
    k_pts = int(p["K_PTS"])
    a_pts = int(p["A_PTS"])
    b_pts = int(p["B_PTS"])
    c_pts = int(p["C_PTS"])
    d_pts = int(p["D_PTS"])
    e_pts = int(p["E_PTS"])
    f_pts = int(p["F_PTS"])
    g_pts = int(p["G_PTS"])
    length2 = float(p["LENGTH2"])
    radius2 = float(p["RADIUS2"])
    area2 = float(p["AREA2"])

    cmv = [False] * 15

    # LIC 1
    for i in range(numpoints - 1):
        if gt(distance(i, i + 1), length1):
            cmv[0] = True
            break

    # LIC 2
    for i in range(numpoints - 2):
        if cannot_fit_circle(i, i + 1, i + 2, radius1):
            cmv[1] = True
            break

    # LIC 3
    for i in range(numpoints - 2):
        if angle_condition(i, i + 1, i + 2, epsilon):
            cmv[2] = True
            break

    # LIC 4
    for i in range(numpoints - 2):
        if gt(triangle_area(i, i + 1, i + 2), area1):
            cmv[3] = True
            break

    # LIC 5
    for i in range(numpoints - q_pts + 1):
        if len({quadrant(j) for j in range(i, i + q_pts)}) > quads:
            cmv[4] = True
            break

    # LIC 6
    for i in range(numpoints - 1):
        if lt(x[i + 1] - x[i], 0.0):
            cmv[5] = True
            break

    # LIC 7
    if numpoints >= 3:
        for i in range(numpoints - n_pts + 1):
            first = i
            last = i + n_pts - 1

            if point_eq(first, last):
                found = False
                for m in range(first + 1, last):
                    if gt(distance(first, m), dist):
                        found = True
                        break
                if found:
                    cmv[6] = True
                    break
            else:
                found = False
                ax, ay = x[first], y[first]
                bx, by = x[last], y[last]
                for m in range(first + 1, last):
                    dline = point_line_distance(x[m], y[m], ax, ay, bx, by)
                    if gt(dline, dist):
                        found = True
                        break
                if found:
                    cmv[6] = True
                    break

    # LIC 8
    if numpoints >= 3:
        step = k_pts + 1
        for i in range(numpoints - step):
            if gt(distance(i, i + step), length1):
                cmv[7] = True
                break

    # LIC 9
    if numpoints >= 5:
        step1 = a_pts + 1
        step2 = b_pts + 1
        total = step1 + step2
        for i in range(numpoints - total):
            j = i + step1
            k = j + step2
            if cannot_fit_circle(i, j, k, radius1):
                cmv[8] = True
                break

    # LIC 10
    if numpoints >= 5:
        step1 = c_pts + 1
        step2 = d_pts + 1
        total = step1 + step2
        for i in range(numpoints - total):
            j = i + step1
            k = j + step2
            if angle_condition(i, j, k, epsilon):
                cmv[9] = True
                break

    # LIC 11
    if numpoints >= 5:
        step1 = e_pts + 1
        step2 = f_pts + 1
        total = step1 + step2
        for i in range(numpoints - total):
            j = i + step1
            k = j + step2
            if gt(triangle_area(i, j, k), area1):
                cmv[10] = True
                break

    # LIC 12
    if numpoints >= 3:
        step = g_pts + 1
        for i in range(numpoints - step):
            if lt(x[i + step] - x[i], 0.0):
                cmv[11] = True
                break

    # LIC 13
    if numpoints >= 3:
        step = k_pts + 1
        has_greater = False
        has_less = False
        for i in range(numpoints - step):
            d = distance(i, i + step)
            if gt(d, length1):
                has_greater = True
            if lt(d, length2):
                has_less = True
            if has_greater and has_less:
                cmv[12] = True
                break

    # LIC 14
    if numpoints >= 5:
        step1 = a_pts + 1
        step2 = b_pts + 1
        total = step1 + step2
        has_outside_r1 = False
        has_inside_r2 = False
        for i in range(numpoints - total):
            j = i + step1
            k = j + step2
            needed = required_circle_radius(i, j, k)
            if gt(needed, radius1):
                has_outside_r1 = True
            if not gt(needed, radius2):
                has_inside_r2 = True
            if has_outside_r1 and has_inside_r2:
                cmv[13] = True
                break

    # LIC 15
    if numpoints >= 5:
        step1 = e_pts + 1
        step2 = f_pts + 1
        total = step1 + step2
        has_greater_a1 = False
        has_less_a2 = False
        for i in range(numpoints - total):
            j = i + step1
            k = j + step2
            a = triangle_area(i, j, k)
            if gt(a, area1):
                has_greater_a1 = True
            if lt(a, area2):
                has_less_a2 = True
            if has_greater_a1 and has_less_a2:
                cmv[14] = True
                break

    pum = [[False] * 15 for _ in range(15)]
    for i in range(15):
        for j in range(15):
            if i == j:
                pum[i][j] = bool(pum_diag[i])
                continue

            connector = lcm[i][j]
            if connector == "NOTUSED":
                pum[i][j] = True
            elif connector == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            elif connector == "ORR":
                pum[i][j] = cmv[i] or cmv[j]
            else:
                raise ValueError(f"Invalid LCM connector: {connector!r}")

    fuv = [False] * 15
    for i in range(15):
        if not pum[i][i]:
            fuv[i] = True
        else:
            fuv[i] = all(pum[i][j] for j in range(15))

    launch = all(fuv)
    return cmv, pum, fuv, launch
